components.css:
.ds-btn-action { width: 100%; display: flex; align-items: center; justify-content: center; gap: 8px; py: 8px; padding: 10px 16px; border-radius: 6px; font-weight: 500; font-family: Inter, sans-serif; font-size: 13px; border: 1px solid transparent; transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1); cursor: pointer; }
.ds-action-active { background: #f8fafc; color: #475569; }
.ds-action-active:hover { background: #0070dc; color: #ffffff; }
.ds-action-incart { background: rgba(0, 112, 220, 0.1); color: #0070dc; border-color: rgba(0, 112, 220, 0.2); }
.ds-action-disabled { background: #f8fafc; color: #94a3b8; cursor: not-allowed; }

.ds-product-card { position: relative; background: #ffffff; border: 1px solid #e2e8f0; border-radius: 6px; width: 280px; overflow: hidden; font-family: Inter, sans-serif; cursor: pointer; transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1); }
.ds-product-card:hover { border-color: #0070dc; box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.05), 0 4px 6px -4px rgba(0, 0, 0, 0.05); }
.ds-card-badge-top { position: absolute; top: 12px; left: 12px; bg-color: #0070dc; background: #0070dc; color: #ffffff; font-size: 10px; font-weight: 700; px: 8px; padding: 4px 8px; border-radius: 2px; z-index: 2; letter-spacing: 0.05em; }
.ds-card-badge-discount { position: absolute; top: 38px; left: 12px; background: #facc15; color: #041e42; font-size: 10px; font-weight: 700; padding: 4px 8px; border-radius: 2px; z-index: 2; letter-spacing: 0.05em; }
.ds-card-image-wrapper { background: #f8fafc; height: 180px; width: 100%; display: flex; align-items: center; justify-content: center; transition: all 0.3s ease; overflow: hidden; }
.ds-product-card:hover .ds-card-image-placeholder { transform: scale(1.08); }
.ds-card-image-placeholder { width: 64px; height: 64px; transition: transform 0.3s ease; }
.ds-card-content { padding: 16px; }
.ds-card-brand { font-size: 10px; color: #94a3b8; text-transform: uppercase; font-weight: 600; letter-spacing: 0.05em; margin-bottom: 4px; }
.ds-card-title { font-size: 14px; font-weight: 500; color: #0f172a; line-height: 1.4; margin-bottom: 8px; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; height: 40px; }
.ds-card-rating { display: flex; align-items: center; gap: 6px; margin-bottom: 8px; }
.ds-stars { color: #facc15; font-size: 14px; }
.ds-rating-val { font-size: 11px; color: #64748b; }
.ds-card-price-row { display: flex; align-items: center; gap: 8px; margin-bottom: 8px; }
.ds-price-old { text-decoration: line-through; color: #94a3b8; font-size: 13px; }
.ds-price-current { color: #0070dc; font-weight: 700; font-size: 16px; }
.ds-card-stock { font-size: 11px; color: #16a34a; font-weight: 500; margin-bottom: 12px; }
.ds-card-btn-cart { width: 100%; display: flex; align-items: center; justify-content: center; background: #f8fafc; color: #475569; padding: 10px 16px; border-radius: 6px; border: none; font-size: 13px; font-weight: 500; cursor: pointer; transition: all 0.2s ease; }
.ds-product-card:hover .ds-card-btn-cart { background: #0070dc; color: #ffffff; }
